mapper.select:
select r.*, case when r.type = 'article' then i.title when r.type = 'post' then p.title when r.type = 'news' then n.title else '' end as introductionTitle from `reply` r left join `introduction` i on r.type = 'article' and r.introduction_id = i.id left join `post` p on r.type = 'post' and r.introduction_id = p.id left join `news` n on r.type = 'news' and r.introduction_id = n.id where r.user_id = #{userId}
and r.type = #{type}
order by r.time desc
